trait CredentialsProvider {
  def getAwsCredentials: AwsCredentialsProvider
}

class EnvironmentCredentialsProvider extends CredentialsProvider {
  override def getAwsCredentials: AwsCredentialsProvider = {
    val accessKey = sys.env.get("AWS_ACCESS_KEY_ID")
    val secretKey = sys.env.get("AWS_SECRET_ACCESS_KEY")
    val sessionToken = sys.env.get("AWS_SESSION_TOKEN")

    (accessKey, secretKey) match {
      case (Some(ak), Some(sk)) =>
        sessionToken match {
          case Some(st) =>
            StaticCredentialsProvider.create(
              AwsSessionCredentials.create(ak, sk, st)
            )
          case None =>
            StaticCredentialsProvider.create(
              AwsBasicCredentials.create(ak, sk)
            )
        }
      case _ =>
        DefaultCredentialsProvider.create()
    }
  }
}

class SecretsManagerCredentialsProvider(region: Region, secretName: String) extends CredentialsProvider {
  private val objectMapper = new ObjectMapper()

  override def getAwsCredentials: AwsCredentialsProvider = {
    val defaultProvider = DefaultCredentialsProvider.create()
    
    val secretsClient = SecretsManagerClient.builder()
      .region(region)
      .credentialsProvider(defaultProvider)
      .build()

    try {
      val getSecretValueRequest = GetSecretValueRequest.builder()
        .secretId(secretName)
        .build()

      val getSecretValueResponse = secretsClient.getSecretValue(getSecretValueRequest)
      val secret = getSecretValueResponse.secretString()

      val secretMap = objectMapper.readValue(secret, classOf[java.util.Map[String, String]]).asScala

      val accessKey = secretMap.get("AWS_ACCESS_KEY_ID")
      val secretKey = secretMap.get("AWS_SECRET_ACCESS_KEY")
      val sessionToken = secretMap.get("AWS_SESSION_TOKEN")

      (accessKey, secretKey) match {
        case (Some(ak), Some(sk)) =>
          sessionToken match {
            case Some(st) =>
              StaticCredentialsProvider.create(
                AwsSessionCredentials.create(ak, sk, st)
              )
            case None =>
              StaticCredentialsProvider.create(
                AwsBasicCredentials.create(ak, sk)
              )
          }
        case _ =>
          defaultProvider
      }
    } finally {
      secretsClient.close()
    }
  }
}

class ChainedCredentialsProvider extends CredentialsProvider {
  override def getAwsCredentials: AwsCredentialsProvider = {
    AwsCredentialsProviderChain.builder()
      .credentialsProviders(
        EnvironmentVariableCredentialsProvider.create(),
        SystemPropertyCredentialsProvider.create(),
        WebIdentityTokenFileCredentialsProvider.create(),
        ProfileCredentialsProvider.create(),
        ContainerCredentialsProvider.builder().build(),
        InstanceProfileCredentialsProvider.create()
      )
      .build()
  }
}

